// Build [input, term] o items paginados con afters según totalCount y maxPage

const input = $input.first().json;
const search = input?.data?.marketplaceJobPostingsSearch ?? {};
const totalCount = Number(search.totalCount ?? 0);
const hasNextPage = !!search.pageInfo?.hasNextPage;
const edges = search.edges ?? [];
const api = $('Edit Fields2').first().json.api;

// Term y maxPage desde "Loop Over Items1"
const loopFirst = $('Loop Over Items1')?.first();
const term = loopFirst?.json?.term ?? $json.term ?? 'unknown';
const maxPageRaw = Number(loopFirst?.json?.maxPage);
const maxPage = Number.isFinite(maxPageRaw) && maxPageRaw > 0 ? Math.floor(maxPageRaw) : 1;

// Paginación (page size 50)
const PAGE_SIZE = 50;
const pagesByCount = Math.ceil(totalCount / PAGE_SIZE);
const pagesToFetch = Math.min(pagesByCount, maxPage);
const numAfters = Math.max(0, pagesToFetch - 1);

// SIN páginas extra → devolver un solo item y meter term en data
if (numAfters === 0) {
  const out = JSON.parse(JSON.stringify(input));   // copia segura
  out.data = out.data ?? {};
  out.data.term = term;                             // queda en data.term
  // Si lo preferís adentro del bloque de la búsqueda:
  // out.data.marketplaceJobPostingsSearch._term = term;
  return [{ json: out }];
}

// Con páginas extra → generar afters: "51", "101", "151", ...
const afters = Array.from({ length: numAfters }, (_, i) => String((i + 1) * PAGE_SIZE + 1));

return afters.map(after => ({
  json: { term, after, hasNextPage, edges, api }
}));

// Merge pages' edges into the single item coming from node "upwork"
// Mode: Run Once for All Items

// 1) Incoming pages
const pages = $input.all();
const term = $('HasNextPage and LessThan')?.first()?.json?.term ?? null;

// 2) Base JSON from the "upwork" node (single item with edges array)
const baseJson = $('upwork').first().json;
const baseContainer = baseJson.data?.marketplaceJobPostingsSearch ?? baseJson;
const baseEdges = baseContainer.edges ?? [];

// 3) Collect all new edges from the pages
const newEdges = [];
for (const it of pages) {
  const e = it.json?.data?.marketplaceJobPostingsSearch?.edges ?? it.json?.edges ?? [];
  newEdges.push(...e);
}

// 4) Merge + dedupe by job id (preferring first occurrence)
const getId = (x) => x?.node?.id ?? x?.id ?? x?.job?.id;
const seen = new Set();
const merged = [];
for (const e of [...baseEdges, ...newEdges]) {
  const id = getId(e);
  if (!id || seen.has(id)) continue;
  seen.add(id);
  merged.push(e);
}
baseContainer.edges = merged;

// 5) Carry forward pageInfo/totalCount from last page
const last = pages.at(-1)?.json?.data?.marketplaceJobPostingsSearch;
if (last) {
  baseContainer.pageInfo = last.pageInfo ?? baseContainer.pageInfo;
  baseContainer.totalCount = last.totalCount ?? baseContainer.totalCount;
}

// 5.5) Adjuntá el term dentro de `data` (o usa _term para evitar choques)
baseJson.data = baseJson.data ?? {};
baseJson.data.term = term;        // o: baseContainer._term = term;

// 6) Return: un solo item con todo
return [{ json: baseJson }];

const pages = $input.all();
const nodes = [];

for (const { json } of pages) {
  // ⬅️ term asociado a ESA página
  const pageTerm = json?.data?.term ?? json?.term ?? null;

  const j = json?.data?.marketplaceJobPostingsSearch ?? json?.data ?? json;

  if (Array.isArray(j?.edges)) {
    for (const e of j.edges) {
      const n = e?.node;
      if (n && (n.id || n.jobId || n.job_id)) {
        nodes.push({ ...n, _term: pageTerm });   // ⬅️ guardo el term acá
      }
    }
    continue;
  }

  if (j?.node && (j.node.id || j.node.jobId || j.node.job_id)) {
    nodes.push({ ...j.node, _term: pageTerm });  // ⬅️
    continue;
  }
  if (j?.id || j?.jobId || j?.job_id) {
    nodes.push({ ...j, _term: pageTerm });       // ⬅️
  }
}


// Dedupe by job id
const getId = (r) => r.jobId ?? r.job_id ?? r.id;
const uniq = new Map();
for (const n of nodes) {
  const id = getId(n);
  if (id && !uniq.has(id)) uniq.set(id, n);
}

// Map to your final shape (same as before)
const out = [...uniq.values()].map(node => ({
  json: {
    id: node.id ?? node.jobId ?? node.job_id,
    title: node.title ?? null,
    term: node._term ?? null,
    description: node.description ?? null,
    ciphertext: node.ciphertext ?? null,

    // Duration & Engagement
    duration: node.duration ?? null,
    durationLabel: node.durationLabel ?? null,
    engagement: node.engagement ?? null,

    // Budget & Financial
    amount: node.amount?.rawValue ?? null,
    hourlyBudgetMin: node.hourlyBudgetMin?.rawValue ?? null,
    hourlyBudgetMax: node.hourlyBudgetMax?.rawValue ?? null,
    weeklyBudget: node.weeklyBudget?.rawValue ?? null,

    // Job Details
    recordNumber: node.recordNumber ?? null,
    experienceLevel: node.experienceLevel ?? null,
    category: node.category ?? null,
    subcategory: node.subcategory ?? null,
    freelancersToHire: node.freelancersToHire ?? null,

    // Job Status
    enterprise: node.enterprise ?? null,
    premium: node.premium ?? null,
    applied: node.applied ?? null,
    relevanceEncoded: node.relevanceEncoded ?? null,

    // Timestamps
    createdDateTime: node.createdDateTime ?? null,
    publishedDateTime: node.publishedDateTime ?? null,
    renewedDateTime: node.renewedDateTime ?? null,

    // Client Info
    clientMemberSinceDateTime: node?.client?.memberSinceDateTime ?? null,
    clientTotalHires: node?.client?.totalHires ?? null,
    clientTotalPostedJobs: node?.client?.totalPostedJobs ?? null,
    clientTotalSpent: node?.client?.totalSpent?.rawValue ?? null,
    clientVerification: node?.client?.verificationStatus ?? null,
    clientTotalReviews: node?.client?.totalReviews ?? null,
    clientTotalFeedback: node?.client?.totalFeedback ?? null,
    clientCompanyName: node?.client?.companyName ?? null,
    clientCompanyRid: node?.client?.companyRid ?? null,
    clientEdcUserId: node?.client?.edcUserId ?? null,
    clientLastContractPlatform: node?.client?.lastContractPlatform ?? null,
    clientLastContractRid: node?.client?.lastContractRid ?? null,
    clientLastContractTitle: node?.client?.lastContractTitle ?? null,
    clientHasFinancialPrivacy: node?.client?.hasFinancialPrivacy ?? null,

    // Client Location
    clientCountry: node?.client?.location?.country ?? null,
    clientCity: node?.client?.location?.city ?? null,
    clientState: node?.client?.location?.state ?? null,
    clientTimezone: node?.client?.location?.timezone ?? null,
    clientOffsetToUTC: node?.client?.location?.offsetToUTC ?? null,

    // Relevance & Activity
    totalApplicants: node.totalApplicants ?? null,
    relevanceId: node?.relevance?.id ?? null,
    relevanceEffectiveCandidates: node?.relevance?.effectiveCandidates ?? null,
    relevanceRecommendedCandidates: node?.relevance?.recommendedEffectiveCandidates ?? null,
    relevanceUniqueImpressions: node?.relevance?.uniqueImpressions ?? null,
    relevancePublishTime: node?.relevance?.publishTime ?? null,
    relevanceHoursInactive: node?.relevance?.hoursInactive ?? null,

    // Job Activity
    lastClientActivity: node?.job?.activityStat?.jobActivity?.lastClientActivity ?? null,
    invitesSent: node?.job?.activityStat?.jobActivity?.invitesSent ?? null,
    totalInvitedToInterview: node?.job?.activityStat?.jobActivity?.totalInvitedToInterview ?? null,
    totalHired: node?.job?.activityStat?.jobActivity?.totalHired ?? null,
    totalUnansweredInvites: node?.job?.activityStat?.jobActivity?.totalUnansweredInvites ?? null,
    totalOffered: node?.job?.activityStat?.jobActivity?.totalOffered ?? null,
    totalRecommended: node?.job?.activityStat?.jobActivity?.totalRecommended ?? null,

    // Skills & Occupations
    skills: node?.skills?.map(s => s.name) ?? [],
    skillsPrettyNames: node?.skills?.map(s => s.prettyName) ?? [],
    skillsHighlighted: node?.skills?.map(s => s.highlighted) ?? [],
    occupationsCategoryId: node?.occupations?.category?.id ?? null,
    occupationsCategoryLabel: node?.occupations?.category?.prefLabel ?? null,
    occupationsSubCategories: node?.occupations?.subCategories?.map(s => s?.prefLabel) ?? [],
    occupationsServiceId: node?.occupations?.occupationService?.id ?? null,
    occupationsServiceLabel: node?.occupations?.occupationService?.prefLabel ?? null,

    // Extras
    preferredFreelancerLocation: node.preferredFreelancerLocation ?? [],
    preferredFreelancerLocationMandatory: node.preferredFreelancerLocationMandatory ?? null,
    clientNotSureFields: node.clientNotSureFields ?? [],
    clientPrivateFields: node.clientPrivateFields ?? [],
    hourlyBudgetType: node.hourlyBudgetType ?? null,
    localJobUserDistance: node.localJobUserDistance ?? null,
    totalFreelancersToHire: node.totalFreelancersToHire ?? null,
    teamId: node.teamId ?? null,

    _raw: node,
  }
}));

return out;

const startIndex = 0;
const allItems = $input.all();
const filteredItems = allItems.slice(startIndex);
return filteredItems;

// Extract jobs from input (already flattened)
const jobs = $input.all();

// Process each job to generate URL
const processedJobs = jobs.map(job => {
  // Generate correct job URL format with proper casing and ID prefix
  const jobTitleSlug = job.json.title
    .replace(/[^a-zA-Z0-9\s-]/g, '') // Remove special characters but keep letters
    .replace(/\s+/g, '-') // Replace spaces with hyphens
    .replace(/-+/g, '-') // Replace multiple hyphens with single hyphen
    .trim();

  // Add "02" prefix to the job ID if it doesn't have it
  const jobIdWithPrefix = job.json.id.startsWith('02') ? job.json.id : `02${job.json.id}`;

  const jobUrl = `https://www.upwork.com/freelance-jobs/apply/${jobTitleSlug}_~${jobIdWithPrefix}/`;

  return {
    jobId: job.json.id,
    jobTitle: job.json.title,
    jobUrl: jobUrl
  };
});

// Return each job as a separate item
return processedJobs.map(job => ({
  json: job
}));

const MAX_CALLS = 200;

const items = $input.all();

// Normalizo y guardo original
for (const it of items) {
  const v = Number(it.json?.maxPage);
  it.json.maxPage = Number.isFinite(v) && v > 0 ? Math.floor(v) : 1;
  if (it.json._maxPageOriginal === undefined) {
    it.json._maxPageOriginal = it.json.maxPage;
  }
}

const totalBefore = items.reduce((acc, it) => acc + it.json.maxPage, 0);
if (totalBefore <= MAX_CALLS) {
  return items;
}

let toCut = totalBefore - MAX_CALLS;

// Round-robin: de atrás hacia adelante, restando de a 1
while (toCut > 0) {
  let reduced = false;
  for (let i = items.length - 1; i >= 0 && toCut > 0; i--) {
    const mp = items[i].json.maxPage;
    if (mp > 1) {
      items[i].json.maxPage = mp - 1;
      toCut -= 1;
      reduced = true;
    }
  }
  if (!reduced) break; // todos están en 1
}

// Salvaguarda: si aún excede, ELIMINO ítems del final
if (toCut > 0) {
  for (let i = items.length - 1; i >= 0 && toCut > 0; i--) {
    // eliminar este item reduce el total en items[i].json.maxPage (normalmente 1 acá)
    toCut -= items[i].json.maxPage;
    items.splice(i, 1); // lo saco de la lista
  }
}

return items;

const data = $getWorkflowStaticData('global');
const item = items[0].json;

// If we came from the token call, item contains the token response.
// If we skipped the call, item already has headers from step 1.
if (item.access_token) {
  // Token exchange/refresh response
  data.access_token = item.access_token;
  if (item.refresh_token) data.refresh_token = item.refresh_token; // may not be returned on every refresh
  const now = Math.floor(Date.now() / 1000);
  const ttl = typeof item.expires_in === 'number' ? item.expires_in : 3600;
  data.expires_at = now + ttl - 60; // refresh 1 min early
  return [{ json: { headers: { Authorization: `Bearer ${data.access_token}` } } }];
}

if (item.headers?.Authorization) {
  // No refresh was needed; just forward existing header
  return [{ json: { headers: item.headers } }];
}

throw new Error('SaveToken node: no access token or headers found. Check previous nodes.');

const items = $input.all();

function norm(s) {
  return String(s ?? '')
    .toLowerCase()
    .replace(/[-_]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function isAllowedLocation(loc) {
  // No preference provided → keep
  if (loc == null) return true;

  const arr = Array.isArray(loc) ? loc : [loc];
  if (arr.length === 0) return true;

  // Allowed buckets
  const ok = (s) =>
    s.includes('argentina') ||
    s.includes('south america') ||
    s.includes('latin america') ||
    s.includes('latam') ||
    s.includes('america latina') ||   // ES variants
    s.includes('sudamerica') ||
    s.includes('america del sur') ||
    s.includes('worldwide') ||
    s.includes('global') ||
    s.includes('anywhere') ||
    s.includes('any country') ||
    s.includes('international');

  return arr.some(v => ok(norm(v)));
}

return items.filter(({ json }) => isAllowedLocation(json.preferredFreelancerLocation));

// --- CONFIG ---
const EN = new Set([
  'the','and','for','with','you','your','are','from','this','that','have','has',
  'will','can','need','work','hours','hour','week','weekly','project','looking',
  'experience','development','developer','data','analysis','build','testing',
  'we','our','us','to','of','in','on','is','as','at','by','be','or','not',
  'requirements','responsibilities','deliverables','scope','budget','timeline'
]);

const ES = new Set([
  'de','la','el','y','en','para','por','con','que','los','las','del','al','una','un',
  'como','más','también','será','trabajo','experiencia','desarrollo','desarrollador',
  'datos','análisis','construir','pruebas','requisitos','responsabilidades',
  'entregables','alcance','presupuesto','plazo','horas','semanales','proyecto','buscamos'
]);

// regex: permitimos solo caracteres latinos + tildes/ñ/ü
const allowedRE = /^[a-zA-Z0-9 áéíóúÁÉÍÓÚñÑüÜ¿¡.,;:!?()"'$/\-&%+\[\]{}#*@]|\\r|\\n|\\t]+$/;

function scoreLang(tokens) {
  let enHits = 0, esHits = 0;
  for (const t of tokens) {
    if (EN.has(t)) enHits++;
    if (ES.has(t)) esHits++;
  }
  const n = Math.max(tokens.length, 1);
  return { en: enHits / n, es: esHits / n };
}

// --- MAIN ---
return items
  .map(item => {
    const raw = (item.json.title || '') + ' ' + (item.json.description || '');
    const lower = raw.toLowerCase();

    const alphabetOk = allowedRE.test(raw);
    const tokens = (lower.match(/[a-záéíóúüñ]+/gi) || []).map(t => t.toLowerCase());
    const { en, es } = scoreLang(tokens);

    const hasSpanishDiacritics = /[áéíóúñü¿¡]/i.test(lower);
    const esScore = es + (hasSpanishDiacritics ? 0.02 : 0);

    // Decisión
    let lang = 'other';
    if (alphabetOk) {
      if (en >= 0.02 || esScore >= 0.02) {
        lang = en >= esScore ? 'en' : 'es';
      }
    }

    return { json: { ...item.json, lang } };
  })
  // filtrar: solo inglés o español
  .filter(item => item.json.lang === 'en' || item.json.lang === 'es');

const items = $input.all();

// Palabras/frases que NO querés
const BLOCKLIST = [
  "ugc content",
  "ugc program manager",
  "ai video editor",
  "graphic design",
  "virtual assistant",
  "mechanical engineer",
  "video editor",
  "youtuber",
  "instructor",
  "tour coordinator",
  "tiktoker",
  "reels editor",
  "tutor",
  "teacher",
  "instagrammer",
  "voiceover artist",
  "ad video creator",
  "executive assistant"
];

// Normaliza texto (lowercase + sin acentos)
function normalize(str) {
  return String(str || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

return items.filter(item => {
  const title = normalize(item.json.title);

  // true → lo dejamos pasar
  // false → lo filtramos (bloqueado)
  const isBlocked = BLOCKLIST.some(word =>
    title.includes(word)
  );

  return !isBlocked;
});
